class ComparableValue:
    def __init__(self, value):
        self.value = value

    def __eq__(self, other):
        if isinstance(other, list) and len(other) == 1:
            other = other[0]
        return self.value == other

    def __str__(self):
        return str(self.value)

    def __repr__(self):
        return repr(self.value)

class Account:
    def __init__(self, owner, balance):
        self.owner = owner
        self.balance = ComparableValue(balance)

    def deposit(self, amount):
        self.balance = ComparableValue(self.balance.value + amount)
        return self.balance

account = Account("Mina", 100)
account.deposit(25)

